namespace Puck.Maths;

/// <summary>
/// The tiling word of a metallic-mean quasicrystal, generated by inflation for any index. The n-th metallic mean
/// <c>δₙ = (n + √(n² + 4)) / 2</c> is the quadratic irrational whose all-<c>n</c> continued fraction
/// <c>[n; n, n, …]</c> <see cref="QuadraticInflation"/> reads as the substitution matrix <c>[[n, 1], [1, 0]]</c>; the
/// two-letter substitution <c>long → longⁿ short</c>, <c>short → long</c> with that incidence matrix has a fixed point
/// that is exactly the aperiodic, never-repeating tiling. The golden case <c>n = 1</c> is the Fibonacci chain and the
/// silver case <c>n = 2</c> is the silver-mean (Pell) chain — unified here as two indices of one generator, with the
/// inflation factor <c>δₙ</c> supplied by the shared lens.
/// </summary>
/// <remarks>
/// <see cref="Word(int, Span{bool})"/> fills a run of the word — <see langword="false"/> for the short tile,
/// <see langword="true"/> for the long — as the fixed point of the substitution, so the sequence is self-similar under
/// inflation and identical on every machine. The tiles occur with frequency ratio <c>δₙ : 1</c> (long to short), the
/// right Perron eigenvector of the matrix. <see cref="InflationFactor(int)"/> is <c>δₙ</c> through
/// <see cref="QuadraticInflation.InflationFactor"/>, and <see cref="Positions(int, ReadOnlySpan{bool}, Span{FixedQ4816})"/>
/// lays the tiles on the line with the short tile as the unit and the long tile as <c>δₙ</c> — the one approximate seam,
/// the word above it is exact combinatorics. Beyond streaming, it addresses points by ring coordinate —
/// <see cref="Contains(int, long, long)"/>, <see cref="StartsLongTile(int, long, long)"/>, <see cref="Next(int, long, long)"/>,
/// <see cref="Previous(int, long, long)"/>, and <see cref="Position(int, long, long)"/> — the O(1) membership-and-traversal
/// surface the retired hand-coded golden and silver chains once carried, generalized to every index.
/// </remarks>
public static class MetallicQuasicrystal {
    /// <summary>Fills a leading run of the n-th metallic tiling word: the fixed point of <c>long → longⁿ short</c>, <c>short → long</c>.</summary>
    /// <param name="n">The metallic index; it must be positive. One is the golden (Fibonacci) word, two the silver (Pell) word.</param>
    /// <param name="tiles">Receives the tiling in physical order: <see langword="false"/> is the short tile, <see langword="true"/> the long. Every element is written.</param>
    /// <exception cref="ArgumentOutOfRangeException"><paramref name="n"/> is not positive.</exception>
    public static void Word(int n, Span<bool> tiles) {
        if (0 >= n) {
            throw new ArgumentOutOfRangeException(
                paramName: nameof(n),
                message: "the metallic index must be positive"
            );
        }

        // The metallic mean is the all-n continued fraction, whose single-term period [n] gives the substitution
        // long → longⁿ short, short → long. This is the period-[n] case of the general quadratic quasicrystal.
        QuadraticQuasicrystal.Word(p: n, q: 1L, d: (((long)n * n) + 4L), r: 2L, tiles: tiles);
    }
    /// <summary>Lays a run of the tiling word on the line, returning the start coordinate of each tile.</summary>
    /// <param name="n">The metallic index; it must be positive.</param>
    /// <param name="tiles">The tiling word — as filled by <see cref="Word(int, Span{bool})"/>.</param>
    /// <param name="positions">Receives the start coordinate of each tile, with the short tile as the unit and the long tile as <see cref="InflationFactor(int)"/>. It must be at least as long as <paramref name="tiles"/>.</param>
    /// <returns>The coordinate just past the final tile — the total length of the run.</returns>
    /// <exception cref="ArgumentOutOfRangeException"><paramref name="n"/> is not positive.</exception>
    /// <exception cref="ArgumentException"><paramref name="positions"/> is shorter than <paramref name="tiles"/>.</exception>
    public static FixedQ4816 Positions(int n, ReadOnlySpan<bool> tiles, Span<FixedQ4816> positions) {
        if (positions.Length < tiles.Length) {
            throw new ArgumentException(
                message: "the positions span must be at least as long as the tiling word",
                paramName: nameof(positions)
            );
        }

        var longTile = InflationFactor(n: n);
        var cursor = FixedQ4816.Zero;

        for (var index = 0; (index < tiles.Length); ++index) {
            positions[index] = cursor;
            cursor += (tiles[index] ? longTile : FixedQ4816.One);
        }

        return cursor;
    }
    /// <summary>Returns the inflation factor <c>δₙ = (n + √(n² + 4)) / 2</c> — the long-to-short tile ratio and the self-similarity scale of the word.</summary>
    /// <param name="n">The metallic index; it must be positive.</param>
    /// <returns>The factor as a fixed-point value; the one approximate operation, read through <see cref="QuadraticInflation.InflationFactor"/>.</returns>
    /// <exception cref="ArgumentOutOfRangeException"><paramref name="n"/> is not positive.</exception>
    public static FixedQ4816 InflationFactor(int n) {
        if (0 >= n) {
            throw new ArgumentOutOfRangeException(
                paramName: nameof(n),
                message: "the metallic index must be positive"
            );
        }

        // δₙ is the fundamental unit of the all-n continued fraction (n + √(n² + 4)) / 2.
        return QuadraticInflation.FromQuadraticIrrational(p: n, q: 1L, d: (((long)n * n) + 4L), r: 2L).InflationFactor();
    }
    /// <summary>Determines whether the ring element <c>a + b·δₙ</c> is a vertex of the tiling — the O(1) membership test that addresses points by ring coordinate.</summary>
    /// <param name="n">The metallic index; it must be positive.</param>
    /// <param name="a">The integer part of the ring element.</param>
    /// <param name="b">The coefficient of <c>δₙ</c>.</param>
    /// <returns><see langword="true"/> when the element's Galois conjugate lies in the acceptance window <c>[0, wₙ)</c>. For <c>n = 1</c> this is exactly the classic golden (Fibonacci) membership test.</returns>
    /// <exception cref="ArgumentOutOfRangeException"><paramref name="n"/> is not positive.</exception>
    public static bool Contains(int n, long a, long b) {
        if (0 >= n) {
            throw new ArgumentOutOfRangeException(
                paramName: nameof(n),
                message: "the metallic index must be positive"
            );
        }

        var d = (((long)n * n) + 4L);

        // The conjugate is c = ((2a + bn) − b·√d) / 2; it must satisfy 0 ≤ c < wₙ. The window is wₙ = num / den (both
        // positive), where num and den are the ring elements below — the density-times-covolume length that makes the
        // gaps exactly the two tiles δₙ and δₙ². The membership c < wₙ is num − c·den > 0, tested as a surd sign.
        if (SignSurd(rational: ((2L * a) + (b * n)), coefficient: -b, radicand: d) < 0) { return false; }

        var conjugateRational = (Int128)((2L * a) + (b * n));
        var conjugateSurd = (Int128)(-b);
        var numeratorRational = (((((Int128)n * n * n) + ((Int128)n * n)) + (4L * n)) + 4L);
        var numeratorSurd = ((((Int128)n * n) + n) + 2L);
        var denominatorRational = ((((Int128)n * n * n * n) + (5L * ((Int128)n * n))) + 4L);
        var denominatorSurd = (((Int128)n * n * n) + (3L * n));

        // num − c·den over the common factor of four: the sign is that of this residual surd.
        var residualRational = ((2 * numeratorRational) - ((conjugateRational * denominatorRational) + ((conjugateSurd * denominatorSurd) * d)));
        var residualSurd = ((2 * numeratorSurd) - ((conjugateRational * denominatorSurd) + (conjugateSurd * denominatorRational)));

        return (SignSurd128(rational: residualRational, coefficient: residualSurd, radicand: d) > 0);
    }
    /// <summary>Determines whether the longer tile begins at the vertex <c>a + b·δₙ</c>.</summary>
    /// <param name="n">The metallic index; it must be positive.</param>
    /// <param name="a">The integer part of the vertex.</param>
    /// <param name="b">The coefficient of <c>δₙ</c>.</param>
    /// <returns><see langword="true"/> when the tile starting here is the long one (length <c>δₙ²</c>); otherwise it is the short tile (length <c>δₙ</c>).</returns>
    /// <exception cref="ArgumentOutOfRangeException"><paramref name="n"/> is not positive.</exception>
    public static bool StartsLongTile(int n, long a, long b) =>
        // The short step adds δₙ, reaching (a, b + 1); when that is not a vertex the tile must be the long one instead.
        (Contains(n: n, a: a, b: (b + 1)) == false);
    /// <summary>Returns the next vertex along the line — the far end of the tile that starts at <c>a + b·δₙ</c>.</summary>
    /// <param name="n">The metallic index; it must be positive.</param>
    /// <param name="a">The integer part of a vertex.</param>
    /// <param name="b">The coefficient of <c>δₙ</c>.</param>
    /// <returns>The next vertex, reached by adding <c>δₙ²</c> (a long tile) or <c>δₙ</c> (a short tile).</returns>
    /// <exception cref="ArgumentOutOfRangeException"><paramref name="n"/> is not positive.</exception>
    public static (long A, long B) Next(int n, long a, long b) =>
        // δₙ² = n·δₙ + 1, so the long step lands at (a + 1, b + n); the short step adds δₙ, landing at (a, b + 1).
        (StartsLongTile(n: n, a: a, b: b) ? (a + 1, b + n) : (a, b + 1));
    /// <summary>Returns the previous vertex along the line — the near end of the tile that ends at <c>a + b·δₙ</c>.</summary>
    /// <param name="n">The metallic index; it must be positive.</param>
    /// <param name="a">The integer part of a vertex.</param>
    /// <param name="b">The coefficient of <c>δₙ</c>.</param>
    /// <returns>The preceding vertex of the tiling.</returns>
    /// <exception cref="ArgumentOutOfRangeException"><paramref name="n"/> is not positive.</exception>
    public static (long A, long B) Previous(int n, long a, long b) =>
        // Of the two candidate predecessors, the true one is a vertex whose forward step lands on (a, b); a non-vertex
        // can also step here, so membership and the step must both be checked.
        ((Contains(n: n, a: (a - 1), b: (b - n)) && (Next(n: n, a: (a - 1), b: (b - n)) == (a, b))) ? (a - 1, b - n) : (a, b - 1));
    /// <summary>Returns the position of the vertex <c>a + b·δₙ</c> along the line.</summary>
    /// <param name="n">The metallic index; it must be positive.</param>
    /// <param name="a">The integer part of the vertex.</param>
    /// <param name="b">The coefficient of <c>δₙ</c>.</param>
    /// <returns>The fixed-point coordinate <c>a + b·δₙ</c> — the one approximate value; membership and traversal are exact.</returns>
    /// <exception cref="ArgumentOutOfRangeException"><paramref name="n"/> is not positive.</exception>
    public static FixedQ4816 Position(int n, long a, long b) =>
        (FixedQ4816.FromInteger(value: a) + (FixedQ4816.FromInteger(value: b) * InflationFactor(n: n)));

    /// <summary>Returns the sign of the real number <c>rational + coefficient·√radicand</c>, exactly, by integer arithmetic.</summary>
    private static int SignSurd(long rational, long coefficient, long radicand) =>
        SignSurd128(rational: rational, coefficient: coefficient, radicand: radicand);
    /// <summary>Returns the sign of the real number <c>rational + coefficient·√radicand</c>, exactly, at full width.</summary>
    private static int SignSurd128(Int128 rational, Int128 coefficient, long radicand) {
        if ((rational == Int128.Zero) && (coefficient == Int128.Zero)) { return 0; }
        if ((rational >= Int128.Zero) && (coefficient >= Int128.Zero)) { return 1; }
        if ((rational <= Int128.Zero) && (coefficient <= Int128.Zero)) { return -1; }

        // Opposite signs: compare rational² against radicand·coefficient² at full width, then read off by rational's sign.
        var comparison = (rational * rational).CompareTo((coefficient * coefficient) * radicand);

        return ((rational > Int128.Zero)
            ? ((comparison > 0) ? 1 : ((comparison < 0) ? -1 : 0))
            : ((comparison < 0) ? 1 : ((comparison > 0) ? -1 : 0)));
    }
}
